import { NextResponse } from "next/server"
import type { NextRequest } from "next/server"

const PRIMARY_DOMAIN = "codetales.app"
const REDIRECT_DOMAINS = ["codetale.ai", "www.codetale.ai", "www.codetales.app"]

export function middleware(request: NextRequest) {
  const hostname = request.headers.get("host") || ""
  const hostWithoutPort = hostname.split(":")[0]

  if (REDIRECT_DOMAINS.includes(hostWithoutPort)) {
    const url = request.nextUrl.clone()
    url.host = PRIMARY_DOMAIN
    url.protocol = "https"
    url.port = ""
    return NextResponse.redirect(url, { status: 301 })
  }

  return NextResponse.next()
}

export const config = {
  matcher: [
    "/((?!_next/static|_next/image|favicon.ico|api/audio|api/webhooks).*)",
  ],
}
